def analyze_tool_calls(attempts):
    total = len(attempts)
    if total == 0:
        return {'observed_pass_rate': 0.0, 'true_capability_rate': 0.0, 'gap': 0.0, 'template_problem': False}
    observed = 0
    capable = 0
    for a in attempts:
        if a['capability_ok']:
            capable += 1
            if a['parsed_ok']:
                observed += 1
    observed_rate = round(observed / total, 2)
    capability_rate = round(capable / total, 2)
    gap = round(capability_rate - observed_rate, 2)
    return {'observed_pass_rate': observed_rate, 'true_capability_rate': capability_rate, 'gap': gap, 'template_problem': gap > 0.2}

def analyze_tool_calls(attempts):
    total = len(attempts)
    if not total:
        return {'observed_pass_rate': 0.0, 'true_capability_rate': 0.0, 'gap': 0.0, 'template_problem': False}
    observed = round(sum(a['parsed_ok'] and a['capability_ok'] for a in attempts) / total, 2)
    capable = round(sum(a['capability_ok'] for a in attempts) / total, 2)
    gap = round(capable - observed, 2)
    return {'observed_pass_rate': observed, 'true_capability_rate': capable, 'gap': gap, 'template_problem': gap > 0.2}
